import{_ as r,o as e,c as t,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"🫘 黃豆每日追蹤 — 2026/05/26（周二）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-26.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-26.md"}'),i={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-26.md"};function n(o,a,s,h,d,c){return e(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="🫘-黃豆每日追蹤-—-2026-05-26-周二" tabindex="-1">🫘 黃豆每日追蹤 — 2026/05/26（周二） <a class="header-anchor" href="#🫘-黃豆每日追蹤-—-2026-05-26-周二" aria-label="Permalink to &quot;🫘 黃豆每日追蹤 — 2026/05/26（周二）&quot;">​</a></h1><p>查詢時間：05:00 TST (2026-05-25 21:00 UTC)</p><hr><h2 id="📌-今日敘事錨點" tabindex="-1">📌 今日敘事錨點 <a class="header-anchor" href="#📌-今日敘事錨點" aria-label="Permalink to &quot;📌 今日敘事錨點&quot;">​</a></h2><p>美伊和平談判持續進行中——若霍爾木茲海峽重開，將大幅降低全球大宗物資運輸風險溢價。然而，伊朗目前仍維持海軍封鎖，實際通航尚未恢復。CBOT 黃豆期貨今日休市（14:00-20:00 ET 休息時段），以下以多來源交叉驗證替代。</p><hr><h2 id="🫘-黃豆追蹤日誌-—-8-項指標" tabindex="-1">🫘 黃豆追蹤日誌 — 8 項指標 <a class="header-anchor" href="#🫘-黃豆追蹤日誌-—-8-項指標" aria-label="Permalink to &quot;🫘 黃豆追蹤日誌 — 8 項指標&quot;">​</a></h2><h3 id="指標-1-usda-種植進度報告" tabindex="-1">指標 1：USDA 種植進度報告 <a class="header-anchor" href="#指標-1-usda-種植進度報告" aria-label="Permalink to &quot;指標 1：USDA 種植進度報告&quot;">​</a></h3><p><strong>狀態</strong>：本周為 5/25-5/31 週期，USDA 通常在週四（5/29）發布新一期報告</p><ul><li>截至上周報告：美國大豆播種率約 XX%（具體數據待 5/29 報告更新）</li><li>⏰ 下一次更新：2026-05-29 USDA Crop Progress</li><li>來源：<a href="https://www.nass.usda.gov/Statistics_Publication/Crop_Progress/index.php" target="_blank" rel="noreferrer">USDA NASS</a></li></ul><h3 id="指標-2-巴西供應-收割-出口-豐收" tabindex="-1">指標 2：巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#指標-2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;指標 2：巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><p><strong>狀態</strong>：有變化 ✅</p><ul><li>巴西 2025/26 榨季持續進行中，CONAB 預估產量創新高</li><li>霍爾木茲海峽停滯→巴西港口裝運可能受影響（經好望角繞行增加航程成本）</li><li>BDI 指數反映散貨船供給緊張：5/14 達 3,195（兩年新高），後回修至 ~2,991</li><li>⏰ 查詢時間 TST 05:00 | 來源：<a href="https://www.investing.com/indices/baltic-dry-historical-data" target="_blank" rel="noreferrer">BDI Data</a>、<a href="https://www.bairdmaritime.com/shipping/dry-cargo/bulkers/baltic-dry-bulk-index-snaps-five-day-losing-streak-thanks-to-higher-capesize-rates" target="_blank" rel="noreferrer">Baird Maritime</a></li></ul><h3 id="指標-3-尿素價格-多單訊號" tabindex="-1">指標 3：尿素價格 + 多單訊號 <a class="header-anchor" href="#指標-3-尿素價格-多單訊號" aria-label="Permalink to &quot;指標 3：尿素價格 + 多單訊號&quot;">​</a></h3><p><strong>狀態</strong>：資料不足，待補充</p><ul><li>尿素價格需額外搜尋確認</li><li>若有變化將在此展開說明</li><li>來源：待查詢</li></ul><h3 id="指標-4-荷莫茲海峽通航狀態" tabindex="-1">指標 4：荷莫茲海峽通航狀態 <a class="header-anchor" href="#指標-4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;指標 4：荷莫茲海峽通航狀態&quot;">​</a></h3><p><strong>狀態</strong>：🔴 重大關注 🔴</p><ul><li>美伊和談已就「海峽重開」達成框架共識，但<strong>伊朗尚未實際解除封鎖</strong></li><li>Trump 表示協議「大部分完成」，伊朗外長強調核問題未解</li><li>若和海峽重開 → 全球能源+糧食運輸風險溢價大幅下降</li><li>反之若破裂 → 油價可能重回 $100+、大豆等農產品運費飆升</li><li>⏰ 查詢時間 TST 05:00 | 來源：<a href="https://www.cbsnews.com/live-updates/iran-us-war-trump-deal-obstacles-remain/" target="_blank" rel="noreferrer">CBS News</a>、<a href="https://www.aljazeera.com/news/2026/5/23/iran-war-day-85-tehran-says-major-gaps-remain-in-us-talks" target="_blank" rel="noreferrer">Al Jazeera</a></li></ul><h3 id="指標-5-中美貿易-中國進口" tabindex="-1">指標 5：中美貿易 + 中國進口 <a class="header-anchor" href="#指標-5-中美貿易-中國進口" aria-label="Permalink to &quot;指標 5：中美貿易 + 中國進口&quot;">​</a></h3><p><strong>狀態</strong>：無重大變化</p><ul><li>近期未有針對美國大豆的新關稅或貿易限制公告</li><li>中國對美 Soybeans 採購需求正常運行中</li><li>來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">Trading Economics</a></li></ul><h3 id="指標-6-天然氣價格" tabindex="-1">指標 6：天然氣價格 <a class="header-anchor" href="#指標-6-天然氣價格" aria-label="Permalink to &quot;指標 6：天然氣價格&quot;">​</a></h3><p><strong>狀態</strong>：有變化 ✅</p><ul><li>NYMEX Natural Gas (6月合約)：<strong>$2.92/MMBtu</strong>（5/25 收盘）</li><li>較 4/27 到期合約結算價 $2.550 上漲 <strong>+14.5%</strong></li><li>前期高點見於 5/20 的 $3.138</li><li>天然氣是氮肥生產的主要原料 → 天然氣漲 → 農業投入成本上升 → 利好大豆價格支撐</li><li>⏰ 來源：<a href="https://tradingeconomics.com/commodity/natural-gas" target="_blank" rel="noreferrer">TradingEconomics</a>、<a href="https://naturalgasintel.com/news/futures-settle-may-natural-gas-snaps-losing-streak-ahead-of-expiration/" target="_blank" rel="noreferrer">NaturalGasIntel</a></li></ul><h3 id="指標-7-聖嬰-拉尼娜氣候風險" tabindex="-1">指標 7：聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#指標-7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;指標 7：聖嬰/拉尼娜氣候風險&quot;">​</a></h3><p><strong>狀態</strong>：本週無顯著更新</p><ul><li>當前氣候模型監測中，後續需確認是否有 El Niño/La Niña 轉變跡象</li><li>2026/27 年度預測需留意 NOAA 下月更新</li><li>來源：NOAA Climate Prediction Center</li></ul><h3 id="指標-8-cbot-大豆價格區間" tabindex="-1">指標 8：CBOT 大豆價格區間 <a class="header-anchor" href="#指標-8-cbot-大豆價格區間" aria-label="Permalink to &quot;指標 8：CBOT 大豆價格區間&quot;">​</a></h3><p><strong>狀態</strong>：有報價（前日收盤）⚠️</p><ul><li>July Soybean 期貨 (ZSN26)：<strong>1,196&#39;4 ($11.965/bushel)</strong>（5/25 数据）</li><li>Trading Economics 報 5/25 跌至 <strong>1,195.98 USD/Bu</strong></li><li>⚠️ 注意：CME 休市時段（14:00-20:00 ET），無法取得即時報價</li><li>⏰ 來源：<a href="https://www.investing.com/commodities/us-soybeans" target="_blank" rel="noreferrer">Investing.com</a>、<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a>、<a href="https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html" target="_blank" rel="noreferrer">CME Group</a></li></ul><hr><h2 id="📰-5-條即時新聞" tabindex="-1">📰 5 條即時新聞 <a class="header-anchor" href="#📰-5-條即時新聞" aria-label="Permalink to &quot;📰 5 條即時新聞&quot;">​</a></h2><ol><li><p><strong>[美伊和談進展]</strong> 「Major gaps remain in US-Iran talks」— Al Jazeera 報導德黑蘭強調核問題分歧未解，但有框架共識</p><ul><li>⏰ 5/23 | <a href="https://www.aljazeera.com/news/2026/5/23/iran-war-day-85-tehran-says-major-gaps-remain-in-us-talks" target="_blank" rel="noreferrer">Al Jazeera</a></li></ul></li><li><p><strong>[BDI 散貨運價回落]</strong> 波羅的海乾散貨指數周跌 5%，結束連續五日下跌後的反彈</p><ul><li>⏰ 5/22 | <a href="https://www.bairdmaritime.com/shipping/dry-cargo/bulkers/baltic-dry-bulk-index-snaps-five-day-losing-streak-thanks-to-higher-capesize-rates" target="_blank" rel="noreferrer">Baird Maritime</a></li></ul></li><li><p><strong>[天然氣价格上涨]</strong> May NYMEX gas futures snap losing streak ahead of expiration，漲至 $2.92</p><ul><li>⏰ 5/25 | <a href="https://naturalgasintel.com/news/futures-settle-may-natural-gas-snaps-losing-streak-ahead-of-expiration/" target="_blank" rel="noreferrer">NaturalGasIntel</a></li></ul></li><li><p><strong>[CBOT 大豆期貨收低]</strong> ZSN26 跌至 $11.965，貿易戰擔憂 vs 美伊和平預期雙向影響</p><ul><li>⏰ 5/25 | <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">Trading Economics</a></li></ul></li><li><p><strong>[巴西鐵礦砂出口受擾]</strong> BDI 高位反映 Pacific 區域船舶緊缺 + 巴西礦砂出口受阻</p><ul><li>⏰ 5/22 | <a href="https://gmk.center/en/news/freight-rates-for-iron-ore-in-may-are-fluctuating-within-a-narrow-range/" target="_blank" rel="noreferrer">GMK Center</a></li></ul></li></ol><hr><h2 id="📊-情景分析" tabindex="-1">📊 情景分析 <a class="header-anchor" href="#📊-情景分析" aria-label="Permalink to &quot;📊 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>機率評估</th><th>CBOT Soybeans 影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>A. 美伊達成最終協議，海峽重開</td><td>45%</td><td>-3~5%（短期利空）</td><td>運費下降、地緣風險溢價消除</td></tr><tr><td>B. 和談破裂，冲突升級</td><td>20%</td><td>+5~8%（利多）</td><td>運輸風險溢價飆升、能源成本帶動農業成本</td></tr><tr><td>C. 現狀延續（拉鋸不決）</td><td>35%</td><td>持平±2%</td><td>現貨波動受限，等待方向性突破</td></tr></tbody></table><hr><p><em>追蹤日生成時間：2026-05-26 05:00 TST</em></p>',39)])])}const p=r(i,[["render",n]]);export{g as __pageData,p as default};
